mapper.insert:
/*
	 SQL ID : OrgOrgInfoDAO.insert
	 설  명 : 기관 정보의 정보 등록
*/
INSERT INTO TB_LMS_ORG (
       ORG_ID
     , ORGNM
     , DMNNM
     , SDTTM
     , EDTTM
     , USEYN
     , ORG_SYS_TYCD
     , BBS_BSC_LANG_CD
     , PROD_CD
     , LAYOUT_TPL_CD
     , COLR_TMPLT_CD
     , LIMIT_NOP_CNT
     , TMPLT_ID
     , TOP_LOGO_FILE_ID
     , SBST_LOGO1_FILE_ID
     , SBST_LOGO1_URL
     , SBST_LOGO2_FILE_ID
     , SBST_LOGO2_URL
     , ORG_LOGO_FILE_ID
     , HMPG_FTR
     , ORG_FTR
     , MENU_VRSN
     , EML_ADDR
     , EMLNM
     , RPRS_TELNO
     , CHRGRNM
     , MBR_TYCD
     , RGTR_ID
     , FRST_INQ_DTTM
     , MDFR_ID
     , MOD_DTTM
     , JOIN_USEYN
) VALUES (
       #{orgId}
     , #{orgNm}
     , #{domainNm}
     , #{startDttm}
     , #{endDttm}
     , #{useYn}
     , #{sysTypeCd}
     , #{dfltLangCd}
     , #{productCd}
     , #{layoutTplCd}
     , #{colorTplCd}
     , #{limitNopCnt}
     , #{tplCd}
     , #{topLogoFileSn}
     , #{subLogo1FileSn}
     , #{subLogo1Url}
     , #{subLogo2FileSn}
     , #{subLogo2Url}
     , #{admLogoFileSn}
     , #{wwwFooter}
     , #{admFooter}
     , '0'
     , #{emailAddr}
     , #{emailNm}
     , #{rprstPhoneNo}
     , #{chrgPrsnInfo}
     , #{mbrIdType}
     , #{rgtrId}
     , FN_DTTM()
     , #{mdfrId}
     , FN_DTTM()
     , #{mbrAplcUseYn}
)

mapper.update:
/*
	 SQL ID : OrgOrgInfoDAO.update
	 설  명 : 기관 정보의 정보 수정
*/
UPDATE TB_LMS_ORG
   SET ORGNM = #{orgNm}
     , DMNNM = #{domainNm}
     , SDTTM = #{startDttm}
     , EDTTM = #{endDttm}
     , USEYN = #{useYn}
     , ORG_SYS_TYCD =#{sysTypeCd}
     , BBS_BSC_LANG_CD = #{dfltLangCd}
     , PROD_CD = #{productCd}
     , LIMIT_NOP_CNT = #{limitNopCnt}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
     , JOIN_USEYN = #{mbrAplcUseYn}
 WHERE ORG_ID = #{orgId}

/*
	 SQL ID : OrgOrgInfoDAO.updateInfo
	 설  명 : 기관 정보의 정보 수정
*/
UPDATE TB_LMS_ORG
   SET BBS_BSC_LANG_CD = #{dfltLangCd}
     , EML_ADDR = #{emailAddr}
     , EMLNM = #{emailNm}
     , RPRS_TELNO = #{rprstPhoneNo}
     , CHRGRNM = #{chrgPrsnInfo}
     , MBR_TYCD = #{mbrIdType}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
     , JOIN_USEYN = #{mbrAplcUseYn}
 WHERE ORG_ID = #{orgId}

/*
	 SQL ID : OrgOrgInfoDAO.updateTemplate
	 설  명 : 기관의 템플릿 정보 수정
*/
UPDATE TB_LMS_ORG
   SET LAYOUT_TPL_CD = #{layoutTplCd}
     , COLR_TMPLT_CD = #{colorTplCd}
     , TMPLT_ID = #{tplCd}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE ORG_ID = #{orgId}

/*
	 SQL ID : OrgOrgInfoDAO.updateDesign
	 설  명 : 기관의 디자인 정보 수정
*/
UPDATE TB_LMS_ORG
   SET TOP_LOGO_FILE_ID = #{topLogoFileSn}
     , SBST_LOGO1_FILE_ID = #{subLogo1FileSn}
     , SBST_LOGO1_URL = #{subLogo1Url}
     , SBST_LOGO2_FILE_ID = #{subLogo2FileSn}
     , SBST_LOGO2_URL = #{subLogo2Url}
     , ORG_LOGO_FILE_ID = #{admLogoFileSn}
     , HMPG_FTR = #{wwwFooter}
     , ORG_FTR = #{admFooter}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE ORG_ID = #{orgId}

